(function() {
const SG_CONFIG = {
    // 真实的辉光管(氖气)配色
    COLOR_CORE: "#fff5e0",   
    COLOR_NEON: "#ff4b00",   
    COLOR_HALO: "#ff1100",   
    COLOR_TUBE_BG: "rgba(12, 8, 8, 0.85)", 

    // 动画参数
    SCRAMBLE_DURATION: 4000, 
    FADE_DELAY: 2000         
};

let lastDivergence = null;
let lastDate = null;
let isAnimating = false;

console.log(">> [El Psy Kongroo] 辉光管观测系统(日期汉字版)已启动。");

const styleId = 'sg-meter-style-final-v2';
if (!document.getElementById(styleId)) {
    $('body').append(`
        <style id="${styleId}">
            @import url('https://fonts.googleapis.com/css2?family=Share+Tech+Mono&display=swap');

            #sg-overlay {
                position: fixed; top: 0; left: 0; width: 100vw; height: 100vh;
                background: #000;
                z-index: 2147483647;
                display: flex; flex-direction: column;
                justify-content: center; align-items: center;
                opacity: 0; transition: opacity 0.5s ease-in-out; pointer-events: none;
                /* 增加行与行之间的整体间距 */
                gap: 60px; 
            }

            .sg-active { opacity: 1 !important; pointer-events: auto !important; }

            .meter-row {
                display: flex; gap: 8px;
                justify-content: center; align-items: flex-end;
            }

            /* 日期行样式：稍微缩小，但增加底部间距 */
            .row-date { transform: scale(0.85); opacity: 0.95; }
            /* 变动率行样式：保持巨大 */
            .row-divergence { transform: scale(1.4); }

            .nixie-tube {
                position: relative;
                width: 70px; height: 130px;
                background: ${SG_CONFIG.COLOR_TUBE_BG};
                border-radius: 35px 35px 5px 5px;
                box-shadow: 
                    inset 0 0 15px #000,
                    0 0 10px rgba(0,0,0,0.8);
                display: flex; justify-content: center; align-items: center;
                overflow: hidden;
                border: 1px solid rgba(60, 30, 20, 0.3);
            }

            .nixie-tube::before {
                content: ''; position: absolute; top:0; left:0; width:100%; height:100%;
                background-image: 
                    linear-gradient(rgba(0,0,0,0.7) 1px, transparent 1px),
                    linear-gradient(90deg, rgba(0,0,0,0.7) 1px, transparent 1px);
                background-size: 4px 4px;
                z-index: 2; pointer-events: none; opacity: 0.6;
            }

            .nixie-tube::after {
                content: ''; position: absolute; top: 10%; right: 20%; width: 10px; height: 40%;
                background: linear-gradient(to bottom, rgba(255,255,255,0.1), transparent);
                border-radius: 50px;
                z-index: 3; pointer-events: none;
            }

            .nixie-digit {
                font-family: 'Share Tech Mono', monospace;
                font-size: 5.5rem;
                line-height: 1;
                z-index: 1;
                color: ${SG_CONFIG.COLOR_CORE};
                text-shadow: 
                    0 0 5px ${SG_CONFIG.COLOR_CORE},
                    0 0 15px ${SG_CONFIG.COLOR_NEON},
                    0 0 30px ${SG_CONFIG.COLOR_NEON},
                    0 0 50px ${SG_CONFIG.COLOR_HALO},
                    0 0 80px ${SG_CONFIG.COLOR_HALO};
                opacity: 0.95;
                filter: blur(0.5px) contrast(1.2);
            }

            /* 符号管通用样式 (点、冒号、空格、汉字) */
            .symbol-tube { 
                width: 30px !important; 
                background: transparent !important; 
                box-shadow: none !important; 
                border: none !important; 
            }
            .symbol-tube::before, .symbol-tube::after { display: none; }

            .symbol-digit { 
                font-size: 4rem; margin-top: 40px; 
                color: ${SG_CONFIG.COLOR_NEON};
                text-shadow: 0 0 10px ${SG_CONFIG.COLOR_HALO};
            }

            /* 汉字特殊样式：不需要太宽，但字号要调整 */
            .chinese-tube { width: 50px !important; }
            .chinese-digit {
                font-family: "Microsoft YaHei", sans-serif; /* 汉字用黑体 */
                font-size: 3rem; 
                margin-top: 35px;
                color: ${SG_CONFIG.COLOR_NEON};
                text-shadow: 0 0 15px ${SG_CONFIG.COLOR_HALO};
                font-weight: bold;
            }

            .spacer { width: 30px; }

            .digit-flicker {
                animation: flicker 0.08s infinite;
            }
            @keyframes flicker {
                0% { opacity: 0.85; text-shadow: 0 0 10px ${SG_CONFIG.COLOR_NEON}; }
                50% { opacity: 1.0; text-shadow: 0 0 25px ${SG_CONFIG.COLOR_NEON}, 0 0 50px ${SG_CONFIG.COLOR_HALO}; }
                100% { opacity: 0.9; text-shadow: 0 0 15px ${SG_CONFIG.COLOR_NEON}; }
            }
        </style>
    `);
}

// 辅助函数：构建单行辉光管HTML
const buildRowHTML = (strVal) => {
    if (!strVal) return '';
    const chars = strVal.split('');
    let html = '';

    chars.forEach(char => {
        if (/[0-9]/.test(char)) {
            // 数字管：初始显示8
            html += `<div class="nixie-tube scramble-target" data-val="${char}"><div class="nixie-digit">8</div></div>`;
        } else if (['年', '月', '日'].includes(char)) {
            // 汉字管
            html += `<div class="nixie-tube symbol-tube chinese-tube"><div class="nixie-digit chinese-digit">${char}</div></div>`;
        } else if (char === '.' || char === ':' || char === '/') {
            // 标点符号管
            html += `<div class="nixie-tube symbol-tube"><div class="nixie-digit symbol-digit">${char}</div></div>`;
        } else if (char === ' ') {
            // 空格
            html += `<div class="spacer"></div>`;
        }
    });
    return html;
};

// 格式化日期字符串：将 2010/08/13 12:00:00 -> 2010年08月13日 12:00:00
const formatChineseDate = (rawDate) => {
    if(!rawDate) return "";
    // 正则替换：匹配 YYYY/MM/DD
    return rawDate.replace(/^(\d{4})\/(\d{1,2})\/(\d{1,2})/, "$1年$2月$3日");
};

const playDivergenceSequence = async (divergenceVal, dateVal) => {
    if (isAnimating) return;
    isAnimating = true;

    if ($('#sg-overlay').length === 0) {
        $('body').append(`<div id="sg-overlay"></div>`);
    }
    const $overlay = $('#sg-overlay');
    $overlay.empty(); 

    // 1. 构建日期行 (先进行汉字格式化)
    const formattedDate = formatChineseDate(dateVal);
    const dateHtml = buildRowHTML(formattedDate);
    if (dateHtml) {
        $overlay.append(`<div class="meter-row row-date">${dateHtml}</div>`);
    }

    // 2. 构建变动率行
    const divHtml = buildRowHTML(divergenceVal);
    if (divHtml) {
        $overlay.append(`<div class="meter-row row-divergence">${divHtml}</div>`);
    }

    $overlay.addClass('sg-active');

    const $digits = $('.scramble-target .nixie-digit');
    const duration = SG_CONFIG.SCRAMBLE_DURATION;
    const startTime = Date.now();

    const timer = setInterval(() => {
        const elapsed = Date.now() - startTime;
        const progress = elapsed / duration;

        $digits.each(function(index) {
            const finalNum = $(this).parent().attr('data-val');

            // 动画逻辑：左侧先定格
            if (progress * ($digits.length + 4) > index + Math.random() * 2) {
                $(this).text(finalNum);
                $(this).removeClass('digit-flicker');
                $(this).css('opacity', '1');
            } else {
                $(this).text(Math.floor(Math.random() * 10));
                $(this).addClass('digit-flicker');
            }
        });

        if (elapsed >= duration) {
            clearInterval(timer);
            // 最终修正
            $digits.each(function() {
                $(this).text($(this).parent().attr('data-val')).removeClass('digit-flicker');
            });

            setTimeout(() => {
                $overlay.removeClass('sg-active');
                isAnimating = false;
            }, SG_CONFIG.FADE_DELAY);
        }
    }, 35); 
};

const scanMessage = () => {
    setTimeout(() => {
        const $lastMsg = $('.mes_text').last();
        if ($lastMsg.length === 0) return;
        const text = $lastMsg.html();

        const divMatch = text.match(/(?:&lt;|<)divergence(?:&gt;|>)(.*?)(?:&lt;|<)\/divergence(?:&gt;|>)/);
        const dateMatch = text.match(/(?:&lt;|<)date(?:&gt;|>)(.*?)(?:&lt;|<)\/date(?:&gt;|>)/);

        if (divMatch && divMatch[1]) {
            const currentDivStr = divMatch[1].replace('%', '').trim();
            const currentDateStr = dateMatch && dateMatch[1] ? dateMatch[1].trim() : "";

            if (lastDivergence === null) {
                lastDivergence = currentDivStr;
                lastDate = currentDateStr;
                return;
            }

            if (currentDivStr !== lastDivergence) {
                console.log(`>> [World Line Shift] ${lastDivergence} -> ${currentDivStr}`);
                lastDivergence = currentDivStr;
                lastDate = currentDateStr;
                playDivergenceSequence(currentDivStr, currentDateStr);
            }
        }
    }, 300);
};

if (typeof eventOn === 'function') {
    eventOn(tavern_events.MESSAGE_RECEIVED, scanMessage);
    eventOn(tavern_events.MESSAGE_UPDATED, scanMessage);
} else {
    setInterval(scanMessage, 2000);
}

})();

