    .mem-detail-view { flex: 1; position: relative; background: radial-gradient(circle at center, rgba(255,74,0,0.05) 0%, transparent 70%); border: 1px solid #222; overflow: hidden; display: flex; align-items: flex-end; justify-content: center; }
    #mem-display-img { height: 95%; width: auto; max-width: 90%; object-fit: contain; filter: drop-shadow(0 0 20px rgba(0,0,0,0.8)); opacity: 0; transform: translateX(30px) scale(0.95); transition: all 0.4s cubic-bezier(0.2, 0.8, 0.2, 1); }
    #mem-display-img.show { opacity: 1; transform: translateX(0) scale(1); }
    .mem-info-box { position: absolute; bottom: 30px; right: 30px; background: rgba(0,0,0,0.85); border-right: 4px solid var(--sg-orange); padding: 20px; text-align: right; min-width: 200px; box-shadow: 0 10px 30px #000; opacity: 0; transform: translateY(20px); transition: all 0.3s 0.1s; }
    .mem-info-box.show { opacity: 1; transform: translateY(0); }
    .mi-name { font-size: 32px; color: var(--sg-orange); font-weight: bold; margin-bottom: 10px; text-shadow: 0 0 10px rgba(255, 74, 0, 0.3); }
    .mi-row { font-size: 14px; color: #aaa; margin-bottom: 5px; font-family: var(--font-digit); }
    .mi-val { color: #fff; margin-left: 10px; font-weight: bold; }

    #inv-con { display: grid; grid-template-columns: repeat(auto-fill, minmax(140px, 1fr)); gap: 15px; padding: 10px; overflow-y: auto; }
    .inv-card { background: rgba(10, 20, 15, 0.4); border: 1px solid #333; position: relative; padding: 10px; display: flex; flex-direction: column; align-items: center; text-align: center; transition: all 0.2s; clip-path: polygon(10px 0, 100% 0, 100% calc(100% - 10px), calc(100% - 10px) 100%, 0 100%, 0 10px); box-shadow: inset 0 0 20px rgba(0,0,0,0.5); }
    .inv-card::before { content: ''; position: absolute; inset: 0; background: repeating-linear-gradient(0deg, transparent 0, transparent 2px, rgba(41, 240, 180, 0.05) 3px); pointer-events: none; }
    .inv-card:hover { background: rgba(41, 240, 180, 0.1); border-color: var(--sg-green); box-shadow: 0 0 15px rgba(41, 240, 180, 0.3); transform: translateY(-2px); }
    .inv-icon { font-size: 36px; margin-bottom: 5px; filter: drop-shadow(0 0 5px rgba(255,255,255,0.2)); }
    .inv-name { color: #ddd; font-size: 14px; font-weight: bold; line-height: 1.2; }
    .inv-id { font-family: var(--font-digit); font-size: 10px; color: var(--sg-green); margin-top: 5px; opacity: 0.7; letter-spacing: 1px; }

    #map-wrap { flex: 1; border: 1px solid #333; background: #050505; position: relative; overflow: hidden; cursor: grab; }
    #map-wrap:active { cursor: grabbing; }
    #map-content { position: absolute; top: 0; left: 0; width: 100%; height: 100%; transform-origin: 0 0; transition: transform 0.1s ease-out; }
    #map-img { width: 100%; height: 100%; object-fit: cover; opacity: 0.9; pointer-events: none; }
    .map-group { 
        position: absolute; transform: translate(-50%, -50%); 
        display: flex; flex-direction: column; align-items: center; 
        z-index: 100; transition: all 0.3s cubic-bezier(0.175, 0.885, 0.32, 1.275); 
    }
    .map-group:hover { z-index: 200; transform: translate(-50%, -60%) scale(1.2); }
    .map-avatars-con { 
        display: flex; 
        justify-content: center; 
        align-items: center;
        background: transparent;  /* 去掉背景 */
        border: none;             /* 去掉那个丑的粉色边框 */
        box-shadow: none;         /* 去掉容器阴影 */
        padding: 0;               /* 去掉内边距 */
        margin-bottom: 2px;
        border-radius: 0;
    }

    /* 核心：头像独立悬浮样式 */
    .map-head-img { 
        width: 45px; height: 45px; /* 稍微大一点 */
        border-radius: 50%; 
        border: 2px solid #222;    /* 保持深色边框或者改成 #fff 白色边框看你喜好 */
        margin: 0 -8px;            /* 负边距让头像重叠在一起 */
        background: #333;
        object-fit: cover; 
        object-position: top center; /* 确保显示头部 */
        box-shadow: 0 5px 15px rgba(0,0,0,0.8); 

        transition: transform 0.2s cubic-bezier(0.175, 0.885, 0.32, 1.275), z-index 0s;
        position: relative;
        z-index: 1;
    }
    .map-head-img:hover { 
        transform: scale(1.2) translateY(-5px); 
        z-index: 100; /* 提升层级 */
        border-color: var(--sg-orange); /* 互动变色 */
    }

    /* 玩家指针动画优化 */
    .user-pointer { 
        width: 0; height: 0; 
        border-left: 8px solid transparent; 
        border-right: 8px solid transparent; 
        border-top: 12px solid #db2a0b; 
        filter: drop-shadow(0 2px 4px rgba(0,0,0,0.8)); 
        animation: float-point 1.5s infinite ease-in-out; 
    }
    @keyframes float-point { 0%, 100% { transform: translateY(0); } 50% { transform: translateY(-5px); } }

    #backlog { position: absolute; inset: 0; background: rgba(0,0,0,0.95); z-index: 250; padding: 50px 80px; overflow-y: auto; display: none; }
    #backlog.show { display: block; }
    .bl-entry { margin-bottom: 20px; border-left: 2px solid #333; padding-left: 15px; color: #aaa; cursor: pointer; transition: 0.2s; }
    .bl-entry:hover { border-left-color: var(--sg-orange); color: #fff; background: rgba(255,255,255,0.05); }
    .bl-name { color: var(--sg-orange); font-size: 14px; margin-bottom: 4px; }
    #btn-fs { position: absolute; top: 10px; left: 10px; width: 30px; height: 30px; border: 1px solid #333; color: #666; display: flex; justify-content: center; align-items: center; cursor: pointer; z-index: 999; }
    #btn-fs:hover { color: var(--sg-orange); border-color: var(--sg-orange); }
    /* --- 智能手机短信风格样式 --- */
    .mobile-app-view {
        padding: 0 !important; /* 覆盖默认面板内边距 */
        background: #000;      /* 纯黑背景 */
        display: none;
        flex-direction: column;
        font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
    }

    .mobile-nav {
        height: 60px;
        background: rgba(20, 20, 20, 0.95);
        border-bottom: 1px solid #333;
        display: flex;
        align-items: center;
        justify-content: space-between;
        padding: 0 15px;
        color: #007aff; /* iOS 蓝 */
        font-size: 17px;
        flex-shrink: 0;
        z-index: 10;
    }

    .nav-title {
        color: #fff;
        font-weight: bold;
        font-size: 16px;
    }

    .nav-right { opacity: 0.5; font-size: 14px; }
    .nav-left { cursor: pointer; display: flex; align-items: center; gap: 5px; }

    .mobile-content-area {
        flex: 1;
        padding: 20px;
        overflow-y: auto;
        display: flex;
        flex-direction: column;
        gap: 20px;
    }

    .msg-timestamp {
        text-align: center;
        color: #666;
        font-size: 12px;
        margin-bottom: 10px;
    }

    .msg-row {
        display: flex;
        align-items: flex-end;
        gap: 10px;
    }

    .msg-avatar {
        width: 35px; height: 35px;
        background: #333;
        border-radius: 50%;
        color: #aaa;
        display: flex; justify-content: center; align-items: center;
        font-size: 18px;
        font-weight: bold;
    }

    .msg-bubble {
        max-width: 70%;
        padding: 12px 16px;
        border-radius: 20px;
        font-size: 16px;
        line-height: 1.4;
        position: relative;
        word-wrap: break-word;
    }

    .msg-bubble.received {
        background: #262628; /* 深灰气泡 */
        color: #fff;
        border-bottom-left-radius: 5px; /* 气泡小尾巴效果 */
    }

    /* 底部输入栏模拟 */
    .mobile-input-bar {
        height: 50px;
        background: #111;
        border-top: 1px solid #333;
        display: flex;
        align-items: center;
        padding: 0 15px;
        gap: 15px;
        flex-shrink: 0;
    }
    .cam-icon { color: #666; font-size: 20px; }
    .input-fake {
        flex: 1;
        height: 32px;
        border: 1px solid #333;
        border-radius: 16px;
        padding: 0 12px;
        line-height: 30px;
        font-size: 14px;
        color: #555;
    }
    .send-btn { color: #007aff; font-weight: bold; font-size: 15px; opacity: 0.5; }
    /* --- 智能手机通讯录风格 --- */
    .contact-search-bar {
        background: #111;
        padding: 10px 15px;
        border-bottom: 1px solid #333;
    }
    .search-input {
        background: #222;
        color: #666;
        height: 36px;
        border-radius: 10px;
        display: flex;
        align-items: center;
        padding-left: 10px;
        font-size: 14px;
    }

    .contact-list {
        display: flex;
        flex-direction: column;
        padding-bottom: 50px;
    }

    .contact-row {
        display: flex;
        align-items: center;
        padding: 12px 15px;
        border-bottom: 1px solid #222;
        background: #000;
        transition: background 0.2s;
    }
    .contact-row:active {
        background: #1a1a1a;
    }

    .c-avatar {
        width: 50px; height: 50px;
        border-radius: 50%;
        background: #333;
        object-fit: cover;
        object-position: top center; /* 确保截取头部 */
        margin-right: 15px;
        border: 1px solid #333;
    }

    .c-avatar-placeholder {
        width: 50px; height: 50px;
        border-radius: 50%;
        background: linear-gradient(135deg, #444, #222);
        display: flex; justify-content: center; align-items: center;
        font-weight: bold; font-size: 20px; color: #888;
        margin-right: 15px;
    }

    .c-info {
        flex: 1;
        display: flex;
        flex-direction: column;
        justify-content: center;
        gap: 4px;
    }

    .c-top-line {
        display: flex;
        justify-content: space-between;
        align-items: center;
    }

    .c-name {
        color: #fff;
        font-size: 17px;
        font-weight: bold;
    }

    .c-aff {
        color: #ff4a00; /* 好感度颜色 */
        font-size: 12px;
        font-family: var(--font-digit);
        background: rgba(255, 74, 0, 0.1);
        padding: 2px 6px;
        border-radius: 4px;
    }

    .c-status {
        font-size: 13px;
        color: #888;
        display: flex;
        align-items: center;
        gap: 5px;
    }
    .c-status-dot {
        width: 8px; height: 8px;
        border-radius: 50%;
        background: #666;
    }
    .c-status-dot.active { background: #29f0b4; box-shadow: 0 0 5px #29f0b4; } 
    .c-status-dot.danger { background: #ff0000; box-shadow: 0 0 5px #ff0000; } 
    /* --- 动态状态栏样式 --- */
    .ph-left-group { display: flex; align-items: center; gap: 5px; }

    /* 信号条 */
    .ph-signal-bars { display: flex; align-items: flex-end; gap: 2px; height: 12px; }
    .sig-bar { width: 3px; background: #444; border-radius: 1px; transition: background 0.2s; }
    .sig-bar.active { background: #fff; }
    .sig-bar.b1 { height: 30%; }
    .sig-bar.b2 { height: 50%; }
    .sig-bar.b3 { height: 75%; }
    .sig-bar.b4 { height: 100%; }

    /* 电池组 */
    .ph-battery-group { display: flex; align-items: center; gap: 4px; cursor: pointer; }
    .bat-icon {
        width: 22px; height: 10px;
        border: 1px solid #aaa; border-radius: 2px;
        padding: 1px; position: relative;
        display: flex; align-items: center;
    }
    .bat-icon::after {
        content: ''; position: absolute; right: -3px; top: 2px;
        width: 2px; height: 4px; background: #aaa; border-radius: 0 1px 1px 0;
    }
    .bat-fill {
        width: 100%; height: 100%;
        background: #fff;
        transition: width 0.3s, background 0.3s;
    }
    /* 低电量红色 */
    .bat-fill.low { background: #ff3b30 !important; }
    /* 充电中绿色 */
    .bat-fill.charging { background: #34c759 !important; }

    .bat-bolt {
        position: absolute; left: 50%; top: 50%; transform: translate(-50%, -50%);
        font-size: 10px; color: #000; display: none;
    }
    .bat-fill.charging + .bat-bolt { display: block; }
</style>
</head>
<body>

<div id="raw-data-store">$0</div>

<div id="app-root">
    <div id="bg-layer"></div>

    <div id="sprite-layer">
        <img id="sp-left" class="char-sprite" src="">
        <img id="sp-right" class="char-sprite" src="">
    </div>

    <div id="dialogue-layer">
        <div class="msg-bg"></div>
        <div class="msg-content">
            <div id="ctrl-bar">
                <div class="ctrl-btn" onclick="Game.prev()">◀ Back</div>
                <div class="ctrl-btn" id="btn-auto" onclick="Game.toggleAuto()">Auto</div>
                <div class="ctrl-btn" onclick="Game.next()">Next ▶</div>
            </div>
            <div id="speaker-name"></div>
            <div id="msg-text"></div>
        </div>
    </div>

    <!-- 手机 UI (App Grid) -->
    <div id="phone-ui">
        <div class="ph-screen">
            <div class="ph-status-bar">
                <div class="ph-left-group">
                    <div class="ph-signal-bars" id="signal-con">
                        <div class="sig-bar b1 active"></div>
                        <div class="sig-bar b2 active"></div>
                        <div class="sig-bar b3 active"></div>
                        <div class="sig-bar b4"></div>
                    </div>
                    <span style="font-size:10px; margin-left:4px;">docomo 4G</span>
                </div>

                <!-- 点击电池可以充电 -->
                <div class="ph-battery-group" onclick="BatterySys.toggleCharge()">
                    <span id="bat-val">100%</span>
                    <div class="bat-icon">
                        <div class="bat-fill" id="bat-fill"></div>
                        <div class="bat-bolt" id="bat-bolt">⚡</div>
                    </div>
                </div>
            </div>

            <!-- 桌面 Widget -->
            <div class="ph-widget">
                <span id="ph-time">12:00</span>
                <span id="ph-date">2010/07/28</span>
            </div>

            <!-- App 列表 -->
            <div class="ph-grid">
                <div class="app-item" onclick="UI.panel('worldline')">
                    <div class="app-icon icon-wl">🔮</div>
                    <div class="app-label">世界线</div>
                </div>
                <div class="app-item" onclick="UI.panel('mem')">
                    <div class="app-icon icon-mem">👥</div>
                    <div class="app-label">通讯录</div>
                </div>
                <div class="app-item" onclick="UI.panel('inv')">
                    <div class="app-icon icon-inv">🎒</div>
                    <div class="app-label">背包</div>
                </div>
                <div class="app-item" onclick="UI.panel('map')">
                    <div class="app-icon icon-map">🗺️</div>
                    <div class="app-label">地图</div>
                </div>
                <div class="app-item" onclick="UI.panel('config')">
                    <div class="app-icon icon-set">⚙️</div>
                    <div class="app-label">设置</div>
                </div>
            </div>

            <!-- 底部 Dock 栏 -->
            <div class="ph-dock">
                <div class="app-item" onclick="UI.panel('dialer')">
                    <div class="app-icon" style="background:#34c759; font-size:20px;">📞</div>
                </div>
                <div class="app-item" onclick="UI.panel('dmail')">
                    <div class="app-icon" style="background:#3498db; font-size:20px;">✉️</div>
                </div>
                <div class="app-item">
                    <div class="app-icon" style="background:#9b59b6; font-size:20px;">🌐</div>
                </div>
            </div>
        </div>
        <div class="ph-footer-tip">右键关闭 / 滚轮历史</div>
    </div>

    <!-- 面板区域 -->
    <div id="panel-worldline" class="fs-panel">
        <div class="p-head">DIVERGENCE METER <span class="p-close" onclick="UI.closePanel()">×</span></div>
        <div class="wl-container">
            <div class="nixie-display" id="wl-tubes">
                <div class="nixie-digit">1</div><div class="nixie-digit">.</div><div class="nixie-digit">0</div>
                <div class="nixie-digit">4</div><div class="nixie-digit">8</div><div class="nixie-digit">5</div>
                <div class="nixie-digit">9</div><div class="nixie-digit">6</div>
            </div>
            <div class="wl-info">
                <span>LINE: <span class="wl-val" id="wl-line">Beta</span></span>
                <span>TIME LEAP: <span class="wl-val" id="wl-leap">0</span></span>
            </div>
        </div>
    </div>

    <div id="panel-mem" class="fs-panel mobile-app-view">
        <!-- 顶部导航 -->
        <div class="mobile-nav">
            <div class="nav-left" onclick="UI.closePanel()">
                <span style="font-size:20px">‹</span> 
                <span>返回</span>
            </div>
            <div class="nav-title">通讯录</div>
            <div class="nav-right" style="font-size:20px">+</div>
        </div>

        <!-- 模拟搜索栏 -->
        <div class="contact-search-bar">
            <div class="search-input">🔍 搜索联系人</div>
        </div>

        <!-- 列表容器 -->
        <div class="mobile-content-area" style="padding: 0;">
            <div class="contact-list" id="mem-list">
                <!-- JS 会自动生成联系人条目 -->
            </div>
        </div>
    </div>

    <div id="panel-inv" class="fs-panel">
        <div class="p-head">INVENTORY <span class="p-close" onclick="UI.closePanel()">×</span></div>
        <div style="text-align:center; font-family:var(--font-digit); font-size:32px; color:var(--sg-orange); margin-bottom:20px; text-shadow:0 0 10px rgba(255,74,0,0.5);">
            FUNDS: ¥ <span id="val-yen">0</span>
        </div>
        <div id="inv-con"></div>
    </div>

    <div id="panel-map" class="fs-panel">
        <div class="p-head">LOCATION <span class="p-close" onclick="UI.closePanel()">×</span></div>
        <div id="map-wrap">
            <div id="map-content">
                <img id="map-img" src="https://files.catbox.moe/rkpxwk.png">
                <div id="map-pins"></div>
            </div>
        </div>
    </div>

    <div id="panel-config" class="fs-panel">
        <div class="p-head">SYSTEM CONFIG <span class="p-close" onclick="UI.closePanel()">×</span></div>
        <div style="width: 80%; max-width: 500px; margin: 0 auto; padding-top: 50px;">
            <div class="config-row">
                <div class="config-label"><span>BGM VOLUME</span><span id="vol-bgm-val">20%</span></div>
                <input type="range" id="inp-bgm" class="config-slider" min="0" max="100" value="20" oninput="AudioSys.setVol('bgm', this.value)">
            </div>
            <div class="config-row">
                <div class="config-label"><span>VOICE VOLUME</span><span id="vol-voice-val">100%</span></div>
                <input type="range" id="inp-voice" class="config-slider" min="0" max="100" value="100" oninput="AudioSys.setVol('voice', this.value)">
            </div>
            <div class="config-row">
                <div class="config-label"><span>SFX / ENV</span><span id="vol-sfx-val">80%</span></div>
                <input type="range" id="inp-sfx" class="config-slider" min="0" max="100" value="80" oninput="AudioSys.setVol('sfx', this.value)">
            </div>
            <div class="config-row" style="margin-top: 40px; border-top: 1px dashed #333; padding-top: 20px;">
                <div class="config-label"><span>SYSTEM WALLPAPER</span></div>

                <input type="file" id="inp-wall" style="display:none" accept="image/*" onchange="UI.uploadWallpaper(this)">

                <div style="display:flex; gap:10px;">
                    <label for="inp-wall" class="ctrl-btn" style="flex:1; text-align:center; padding:10px; display:block;">
                        📂 UPLOAD HD IMAGE
                    </label>
                    <div class="ctrl-btn" style="flex:1; text-align:center; padding:10px;" onclick="UI.resetWallpaper()">
                        ↺ RESET
                    </div>
                </div>
            </div>
        </div>
    </div>
    <div id="panel-dmail" class="fs-panel mobile-app-view">
        <!-- 顶部导航栏 -->
        <div class="mobile-nav">
            <div class="nav-left" onclick="UI.closePanel()">
                <span style="font-size:20px">‹</span> 
                <span>信息(1)</span>
            </div>
            <div class="nav-title">Mail</div>
            <div class="nav-right">联系人</div>
        </div>

        <!-- 短信内容区域 -->
        <div class="mobile-content-area">
            <!-- 时间戳标签 -->
            <div class="msg-timestamp" id="dm-header-date">2010/07/28</div>

            <!-- 对方发送的气泡 -->
            <div class="msg-row">
                <div class="msg-avatar">?</div> <!-- 头像 -->
                <div class="msg-bubble received">
                    <div id="dm-text">无邮件内容</div>
                </div>
            </div>
        </div>
        <div class="mobile-input-bar">
            <div class="cam-icon">📷</div>
            <div class="input-fake">D-Mail 仅限接收...</div>
            <div class="send-btn">发送</div>
        </div>
    </div>
    <div id="panel-dialer" class="fs-panel mobile-app-view">
        <div class="mobile-nav" style="border:none; justify-content:center;">
            <div class="nav-title" style="font-weight:normal; opacity:0.7;">Keypad</div>
            <div class="nav-right" onclick="UI.closePanel()" style="position:absolute; right:15px; cursor:pointer;">取消</div>
        </div>

        <!-- 拨号显示区域 -->
        <div class="dialer-display-area">
            <div id="dial-num-display"></div>
            <div id="dial-suggestion">添加到联系人</div>
        </div>

        <!-- 键盘区域 -->
        <div class="dialer-pad">
            <div class="dial-row">
                <div class="dial-btn" onclick="UI.dialInput('1')">1</div>
                <div class="dial-btn" onclick="UI.dialInput('2')">2<span class="sub-txt">ABC</span></div>
                <div class="dial-btn" onclick="UI.dialInput('3')">3<span class="sub-txt">DEF</span></div>
            </div>
