const AssetMgr = {
    cache: {}, 
    getFullUrl(str) {
        if(!str) return "";
        return str.startsWith('http') ? str : CONFIG.BASE_URL + str;
    },
    getOrRaw(url) {
        const full = this.getFullUrl(url);
        return this.cache[full] || full;
    },
    backgroundCache(url) {
        const full = this.getFullUrl(url);
        if (!full || this.cache[full]) return; 
        fetch(full).then(res => res.blob()).then(blob => { this.cache[full] = URL.createObjectURL(blob); }).catch(() => {}); 
    },
    preloadNext(scriptData, currentIndex) {
        const LOOK_AHEAD = 5;
        for(let i = currentIndex + 1; i < Math.min(currentIndex + LOOK_AHEAD, scriptData.length); i++) {
            const line = scriptData[i];
            if(line.sound) this.backgroundCache(line.sound);
            if(line.img) this.backgroundCache(line.img);
        }
    }
};

function findBestMatch(fullLocationString, configObj) {
    if (!fullLocationString) return null;

    const parts = fullLocationString.split(/[\/\-]/).filter(p => p.trim());
    for (let i = parts.length - 1; i >= 0; i--) {
        const part = parts[i];
        let bestKey = null;
        let maxLen = 0;

        for (const key in configObj) {
            if (part.includes(key)) {
                if (key.length > maxLen) {
                    maxLen = key.length;
                    bestKey = key;
                }
            }
        }

        if (bestKey) return bestKey;
    }
    return null; 
}

