        if (name.includes(key) || name.toLowerCase().includes(key.toLowerCase())) {
            return ITEM_ICONS[key];
        }
    }
    return '📦';
}
const WallpaperDB = {
    dbName: "SteinsGate_System_v1",
    storeName: "settings",
    key: "phone_wallpaper",
    db: null,

    init() {
        return new Promise((resolve, reject) => {
            const request = indexedDB.open(this.dbName, 1);

            request.onupgradeneeded = (event) => {
                const db = event.target.result;
                // 创建一个对象仓库，如果不存在的话
                if (!db.objectStoreNames.contains(this.storeName)) {
                    db.createObjectStore(this.storeName);
                }
            };

            request.onsuccess = (event) => {
                this.db = event.target.result;
                resolve(this.db);
            };

            request.onerror = (event) => {
                console.error("IndexedDB error:", event.target.error);
                reject(event.target.error);
            };
        });
    },

    // 2. 保存图片文件 (Blob)
    save(fileBlob) {
        if (!this.db) return;
        const tx = this.db.transaction(this.storeName, "readwrite");
        const store = tx.objectStore(this.storeName);
        store.put(fileBlob, this.key);
    },

    // 3. 读取图片并应用
    loadAndApply(element) {
        if (!this.db) return;
        const tx = this.db.transaction(this.storeName, "readonly");
        const store = tx.objectStore(this.storeName);
        const request = store.get(this.key);

        request.onsuccess = () => {
            const blob = request.result;
            if (blob) {
                // 创建一个临时的 URL 指向这个 Blob
                const imgUrl = URL.createObjectURL(blob);
                element.style.backgroundImage = `url('${imgUrl}')`;
                element.style.backgroundSize = 'cover';
                element.style.backgroundPosition = 'center';
                // 存储旧 URL 以便之后释放内存 (可选优化)
                element.dataset.bgUrl = imgUrl;
            }
        };
    },

    // 4. 删除图片
    clear() {
        if (!this.db) return;
        const tx = this.db.transaction(this.storeName, "readwrite");
        const store = tx.objectStore(this.storeName);
        store.delete(this.key);
    }
};
const BatterySys = {
    level: 100,
    isCharging: false,
    timer: null,
    sigTimer: null,

    init() {
        // 1. 读取电量缓存
        const savedLevel = localStorage.getItem('sg_battery_level');
        if (savedLevel !== null) this.level = parseFloat(savedLevel);

        // 2. 读取充电状态缓存 (新增)
        const savedState = localStorage.getItem('sg_battery_charging');
        if (savedState === 'true') {
            this.isCharging = true;
        }

        this.timer = setInterval(() => {
            if (this.isCharging) {
                this.changeLevel(10); 
            } else {
                this.changeLevel(-0.5); 
            }
        }, 5000);

        this.simulateSignal();
        this.updateUI();
    },

    changeLevel(amount) {
        this.level = Math.max(0, Math.min(100, this.level + amount));
        this.updateUI();
        localStorage.setItem('sg_battery_level', this.level);
    },

    drain(amount) { if(!this.isCharging) this.changeLevel(-amount); },

    toggleCharge() {
        this.isCharging = !this.isCharging;

        // 写入缓存 (新增)
        localStorage.setItem('sg_battery_charging', this.isCharging);

        if(this.isCharging) {
            AudioSys.playSfx('https://files.catbox.moe/t5zgxd.ogg'); 
        }
        this.updateUI();
    },

    updateUI() {
        const valEl = document.getElementById('bat-val');
        const fillEl = document.getElementById('bat-fill');

        valEl.textContent = Math.floor(this.level) + '%';
        fillEl.style.width = this.level + '%';

        if (this.isCharging) fillEl.className = 'bat-fill charging';
        else if (this.level < 20) fillEl.className = 'bat-fill low';
        else fillEl.className = 'bat-fill';
    },

    simulateSignal() {
        const updateSig = () => {
            const bars = document.querySelectorAll('.sig-bar');
            const strength = Math.random() > 0.8 ? 2 : (Math.random() > 0.5 ? 3 : 4);
            bars.forEach((b, i) => {
                if (i < strength) b.classList.add('active');
                else b.classList.remove('active');
            });
            this.sigTimer = setTimeout(updateSig, 2000 + Math.random() * 4000);
        };
        updateSig();
    }
};
const Data = {
