process(raw) {
        if(raw === this.rawText) return;
        this.rawText = raw;
        const clean = raw.replace(/&lt;/g, '<').replace(/&gt;/g, '>').replace(/&amp;/g, '&');

        // 1. 提取 Content (对话)
        const contentMatch = clean.match(/<content>([\s\S]*?)<\/content>/);
        if(contentMatch) this.parseDialogue(contentMatch[1]);
        else {
            const plain = clean
                .replace(/<state_bar>[\s\S]*?<\/state_bar>/g, "")
                .replace(/<trace>[\s\S]*?<\/trace>/g, "") // 确保 trace 不会被当成对话
                .trim();
            if(plain) this.parseDialogue(plain);
        }

        // 2. 提取 XML 数据 (State Bar)
        const stateMatch = clean.match(/<state_bar>([\s\S]*?)<\/state_bar>/);

        // 3. 提取 Trace (位置)
        const traceMatch = clean.match(/<trace>([\s\S]*?)<\/trace>/);

        // --- 核心修改：暴力提取 D-Mail ---
        // 直接在全文里找 <D>...</D>，不管它在哪里
        const dmailMatch = clean.match(/<D>([\s\S]*?)<\/D>/);

        // 构造 XML 传给解析器
        let xmlString = "";
        if(stateMatch) xmlString += stateMatch[1];
        if(traceMatch) xmlString += `<trace>${traceMatch[1]}</trace>`;
        if(xmlString) this.parseXML(xmlString);

        // --- 单独处理 D-Mail 显示逻辑 ---
        if (dmailMatch && dmailMatch[1]) {
            const dText = dmailMatch[1].trim();
            // 分割内容和时间 (支持 —— 或 --)
            const parts = dText.split(/——|--/);
            const content = parts[0];
            const date = parts[1] || "Unknown Date";

            // 直接更新 DOM
            const elContent = document.getElementById('dm-content');
            if (elContent) elContent.textContent = content;

            const elDate = document.getElementById('dm-date');
            if (elDate) elDate.textContent = date.trim();

            const elTopTime = document.getElementById('dm-top-time');
            if(elTopTime && date.trim() !== "Unknown Date") {
                 // 尝试从日期里提取时间显示在顶部状态栏
                 // 假设格式包含空格，取最后一部分，或者直接不显示
                 elTopTime.textContent = "12:00"; 
            }
        } else {
             // 如果没有 D 标签，显示无邮件
             const elContent = document.getElementById('dm-content');
             if (elContent) elContent.textContent = "(受信箱は空です)"; // 收件箱为空
        }
    },
    parseXML(str) {
        const parser = new DOMParser();
        const doc = parser.parseFromString(`<root>${str}</root>`, "text/xml");
        const get = (t) => doc.querySelector(t)?.textContent || "";

        // 1. 基础数据更新
        this.updateNixieDisplay(get('divergence'));
        const line = get('line');
        const leap = get('leap');
        if(line) document.getElementById('wl-line').textContent = line;
        if(leap) document.getElementById('wl-leap').textContent = leap;
        document.getElementById('val-yen').textContent = get('yen');

        // 2. D-Mail 解析 (保留你之前的 D-Mail 功能)
        let dmailRaw = doc.querySelector('D')?.textContent; 
        if (!dmailRaw) dmailRaw = doc.querySelector('d')?.textContent;
        if (dmailRaw && dmailRaw.trim() !== "") {
            const parts = dmailRaw.split(/——|--/);
            const content = parts[0] ? parts[0].trim() : "无内容";
            const dateStr = parts[1] ? parts[1].trim() : "未知时间";
            const tf = document.getElementById('dm-text'); if(tf) tf.innerText = content;
            const df = document.getElementById('dm-header-date'); if(df) df.innerText = dateStr;
        } else {
            const tf = document.getElementById('dm-text'); if(tf) tf.innerText = "没有收到新的 D-Mail。";
            const df = document.getElementById('dm-header-date'); if(df) df.innerText = "--/--";
        }

        // 3. 时间判定
        const dateStr = get('date');
        let timeState = 'night';
        if(dateStr) {
            const p = dateStr.split(' ');
            document.getElementById('ph-date').textContent = p[0] || "--/--";
            document.getElementById('ph-time').textContent = p[1]?.slice(0,5) || "--:--";
            if(p[1]) {
                const hour = parseInt(p[1].split(':')[0]);
                if(hour >= 5 && hour < 17) timeState = 'morning';
                else if(hour >= 17 && hour < 20) timeState = 'evening';
                else timeState = 'night';
            }
        }

        // ===========================================
        // 4. 高级背景匹配逻辑 (WorldLine + Time + Location)
        // ===========================================
        const loc = get('location');
        let bgUrl = null;

        // 4.1 确定世界线后缀
        let wlSuffix = "";
        if (line) {
            if (line.includes('β') || line.includes('Beta') || line.includes('beta')) wlSuffix = "_beta";
            else if (line.includes('α') || line.includes('Alpha') || line.includes('alpha')) wlSuffix = "_alpha";
            else if (line.includes('Steins;Gate') || line.includes('SG')) wlSuffix = "_sg";
            else if (line.includes('Ω') || line.includes('Omega')) wlSuffix = "_omega";
        }

        // 4.2 查找最匹配的地点Key (例如 "天台")
        // 这里使用了之前修改过的从具体到一般的查找逻辑
        const baseKey = findBestMatch(loc, CONFIG.BG_TIMED);

        if(baseKey) {
            // 4.3 优先尝试 "地点_世界线" (例如 "天台_beta")
            let finalKey = baseKey;
            if (wlSuffix && CONFIG.BG_TIMED[baseKey + wlSuffix]) {
                finalKey = baseKey + wlSuffix;
                // console.log(`[BG] Switched to WorldLine variant: ${finalKey}`);
            }

            // 4.4 根据时间取图
            const specificBg = CONFIG.BG_TIMED[finalKey][timeState];
            if(specificBg) bgUrl = AssetMgr.getFullUrl(specificBg);
        }

        // 4.5 如果时间背景没找到，尝试静态背景 (BGS)
        if(!bgUrl) {
            const bgKey = findBestMatch(loc, CONFIG.BGS);
            if(bgKey) bgUrl = AssetMgr.getFullUrl(CONFIG.BGS[bgKey]);
        }

        // 5. 应用背景
        if(bgUrl) document.getElementById('bg-layer').style.backgroundImage = `url('${bgUrl}')`;

        // 6. 其他更新
        UI.memXML = doc;
        UI.renderInv(get('inventory'));
        UI.renderMap(loc, doc);
        AudioSys.bgm(get('bgm'));
    },
    updateNixieDisplay(valStr) {
        if(!valStr) return;
        const con = document.getElementById('wl-tubes');
        con.innerHTML = '';
        for (let char of valStr) {
            const div = document.createElement('div');
            div.className = 'nixie-digit';
            div.textContent = char;
            con.appendChild(div);
        }
    },
    parseDialogue(text) {
        const lines = text.split('\n').filter(l => l.trim());
        const parsed = [];
        const regex = /\[(.*?)\]\s*\[(.*?)\]\s*\[(.*?)\]\s*\|\s*(.*)$/;
        lines.forEach(l => {
            const m = l.match(regex);
            if(m) {
                if(m[1] && m[2] && m[1] !== '旁白') this.charImages[m[1]] = m[2];
                parsed.push({ name: m[1], img: m[2], sound: m[3], text: m[4] });
            }
        });
        if(parsed.length > 0) Game.loadScenario(parsed);
    }
};

const Game = {
    script: [], index: 0, isAuto: false, autoTimer: null, leftName: null, rightName: null,
    loadScenario(data) {
        if (JSON.stringify(data) === JSON.stringify(this.script)) return;
        data.forEach(line => UI.addToBacklog(line));
        this.script = data;
        this.index = 0;
        this.playCurrent();
    },
    async playCurrent() {
        if(this.index < 0) this.index = 0;
        if(this.index >= this.script.length) { this.stopAuto(); return; }

        const data = this.script[this.index];
        AssetMgr.preloadNext(this.script, this.index);

        AudioSys.analyzeAndPlay(data.text);

        const displayImg = AssetMgr.getOrRaw(data.img);
        this.updateSprites(data.name, displayImg);
        const displaySound = AssetMgr.getOrRaw(data.sound);
        const audioPromise = AudioSys.voice(displaySound); 

        UI.typewrite(data.name, data.text, async () => {
            if(this.isAuto) {
                const duration = await audioPromise; 
                const waitTime = Math.max((duration * 1000) - (UI.typingDuration || 0) + 500, 1500);
                clearTimeout(this.autoTimer);
                this.autoTimer = setTimeout(() => this.next(), waitTime);
            }
        });
    },
    next() { 
        AudioSys.stopSfx();
        if(this.index < this.script.length - 1) { this.index++; this.playCurrent(); } else { this.stopAuto(); } 
    },
    prev() { 
        AudioSys.stopSfx();
        if(this.index > 0) { this.stopAuto(); this.index--; this.playCurrent(); } 
    },
    jumpTo(idx) {
        this.stopAuto();
        const target = this.script.findIndex(l => l.text === idx.text);
        if(target !== -1) { this.index = target; this.playCurrent(); } 
        document.getElementById('backlog').classList.remove('show');
    },
    toggleAuto() { if(this.isAuto) this.stopAuto(); else { this.isAuto = true; document.getElementById('btn-auto').classList.add('active'); if(!UI.isTyping) this.next(); } },
    stopAuto() { this.isAuto = false; document.getElementById('btn-auto').classList.remove('active'); clearTimeout(this.autoTimer); },
    updateSprites(name, img) {
        const L = document.getElementById('sp-left');
        const R = document.getElementById('sp-right');
        if(name === '旁白' || !img || !name) { L.className = 'char-sprite dim'; R.className = 'char-sprite dim'; return; }
        if(this.leftName === name) { L.src = img; L.className = 'char-sprite active'; R.className = 'char-sprite dim'; return; }
        if(this.rightName === name) { R.src = img; R.className = 'char-sprite active'; L.className = 'char-sprite dim'; return; }
        if(!this.leftName) { this.leftName = name; L.src = img; L.className = 'char-sprite active'; R.className = 'char-sprite dim'; } 
        else { this.rightName = this.leftName; R.src = L.src; R.className = 'char-sprite dim'; this.leftName = name; L.src = img; L.className = 'char-sprite active'; }
    }
};

