    getFuzzyCharImg(traceName) {
        if (!traceName) return null;
        if (Data.charImages[traceName]) return AssetMgr.getFullUrl(Data.charImages[traceName]);

        for (let scriptName in Data.charImages) {
            if (scriptName.includes(traceName) || traceName.includes(scriptName)) {
                return AssetMgr.getFullUrl(Data.charImages[scriptName]);
            }
        }
        for(let key in this.DEFAULT_AVATARS) {
            if(traceName.includes(key)) {
                return this.DEFAULT_AVATARS[key];
            }
        }

        return null;
