    renderMap(uLoc, doc) {
        const c = document.getElementById('map-pins'); 
        c.innerHTML = '';
        const groups = {}; 

        // 1. 玩家位置
        const userLocKey = findBestMatch(uLoc, CONFIG.LOCS);
        if(userLocKey) groups[userLocKey] = { user: true, members: [] };

        // 2. 读取 Trace
        const traceRaw = doc.querySelector('trace')?.textContent || "";
        const traceLines = traceRaw.split('\n').map(l => l.trim()).filter(l => l);

        traceLines.forEach(line => {
            const parts = line.split(/[:：]/); 
            if (parts.length < 2) return;

            const name = parts[0].trim();
            const locPath = parts[1].trim(); 

            const key = findBestMatch(locPath, CONFIG.LOCS);

            if (key) {
                if (!groups[key]) groups[key] = { user: false, members: [] };
                if (!groups[key].members.includes(name)) {
                    groups[key].members.push(name);
                }
            }
        });

        // 3. 渲染 DOM
        for(let key in groups) {
            const pos = CONFIG.LOCS[key];
            const gData = groups[key];

            const groupEl = document.createElement('div');
            groupEl.className = 'map-group';
            groupEl.style.left = pos[0] + '%';
            groupEl.style.top = pos[1] + '%';

            if(gData.members.length > 0) {
                const avContainer = document.createElement('div'); 
                avContainer.className = 'map-avatars-con';

                let hasValidImg = false;
                gData.members.forEach(mName => {
                    // 调用修改后的查找逻辑，必定返回链接或null
                    const imgUrl = this.getFuzzyCharImg(mName);

                    if(imgUrl) {
                        const img = document.createElement('img'); 
                        img.className = 'map-head-img'; 
                        img.src = imgUrl; 
                        img.title = mName;
                        // CSS 里的 object-position: top center 会自动截取头部
                        img.onload = function(){ this.classList.add('loaded'); };
                        avContainer.appendChild(img);
                        hasValidImg = true;
                    } 
                    // 这里删除了 else 分支，没图就不显示，不再显示黑色文字圈
                });

                // 只有当至少有一个角色有图时，才把容器加进去
                if(hasValidImg) groupEl.appendChild(avContainer);
            }

            if(gData.user) { 
                const ptr = document.createElement('div'); 
                ptr.className = 'user-pointer'; 
                groupEl.appendChild(ptr); 
            }
            c.appendChild(groupEl);
        }
    },
    initMapEvents() {
        const wrap = document.getElementById('map-wrap');
        wrap.addEventListener('wheel', (e) => { e.preventDefault(); this.mapScale = Math.min(Math.max(1, this.mapScale + e.deltaY * -0.001), 4); this.updateMapTransform(); });
        wrap.addEventListener('mousedown', (e) => { this.isDragging = true; this.startX = e.clientX - this.mapX; this.startY = e.clientY - this.mapY; wrap.style.cursor = 'grabbing'; });
        window.addEventListener('mouseup', () => { this.isDragging = false; if(document.getElementById('map-wrap')) document.getElementById('map-wrap').style.cursor = 'grab'; });
        window.addEventListener('mousemove', (e) => { if(this.isDragging) { e.preventDefault(); this.mapX = e.clientX - this.startX; this.mapY = e.clientY - this.startY; this.updateMapTransform(); } });
    },
    updateMapTransform() {
        const wrap = document.getElementById('map-wrap'); const content = document.getElementById('map-content');
        const w = wrap.clientWidth; const h = wrap.clientHeight;
        const maxX = 0; const minX = w - (w * this.mapScale); const maxY = 0; const minY = h - (h * this.mapScale);
        this.mapX = Math.max(Math.min(this.mapX, maxX), minX); this.mapY = Math.max(Math.min(this.mapY, maxY), minY);
        if(this.mapScale === 1) { this.mapX = 0; this.mapY = 0; }
        content.style.transform = `translate(${this.mapX}px, ${this.mapY}px) scale(${this.mapScale})`;
