        if(saved) {
            try { 
                this.volumes = JSON.parse(saved); 
                console.log("Audio settings loaded from cache:", this.volumes);
            } catch(e) { console.error("Settings load failed", e); }
        }

        // --- 强制应用缓存的音量到音频元素 ---
        const aBgm = document.getElementById('bgm');
        if(aBgm) aBgm.volume = this.volumes.bgm;

        const aVoice = document.getElementById('voice');
        if(aVoice) aVoice.volume = this.volumes.voice;

        const aSfx = document.getElementById('sfx-oneshot');
        if(aSfx) aSfx.volume = this.volumes.sfx;

