            if(elVoice) { elVoice.value = this.volumes.voice * 100; document.getElementById('vol-voice-val').textContent = Math.round(this.volumes.voice * 100) + '%'; }
            if(elSfx) { elSfx.value = this.volumes.sfx * 100; document.getElementById('vol-sfx-val').textContent = Math.round(this.volumes.sfx * 100) + '%'; }
        });
    },
    playUi(type) {
        const el = document.getElementById(type === 'left' ? 'se-click-l' : 'se-click-r');
        if(el) {
