    setVol(type, val) {
        const v = val / 100;
        this.volumes[type] = v;
        document.getElementById(`vol-${type}-val`).textContent = val + '%';
        localStorage.setItem('sg_settings', JSON.stringify(this.volumes));

        if (type === 'bgm') {
            document.getElementById('bgm').volume = v;
        } else if (type === 'voice') {
            document.getElementById('voice').volume = v;
        } else if (type === 'sfx') {
            document.getElementById('sfx-oneshot').volume = v;
            document.getElementById('env-weather').volume = v * 0.8;
            document.getElementById('env-urban').volume = v * 0.8;
            document.getElementById('env-nature').volume = v * 0.8;
        }
