    analyzeAndPlay(text) {
        if (!text) return;

        let foundEnv = { weather: null, urban: null, nature: null };
        let foundSfx = null;
        let foundCmd = null;

        for (const [id, data] of Object.entries(SFX_DB)) {
            for (const key of data.keys) {
                if (text.includes(key)) {
                    if (data.type === 'env') {
                        if (!foundEnv[data.layer]) foundEnv[data.layer] = id;
                    } else if (data.type === 'sfx') {
                        if (!foundSfx) foundSfx = id;
                    } else if (data.type === 'cmd') {
                        foundCmd = id;
                    }
                }
            }
        }

        if (foundCmd === "stop_all") { this.stopAllEnv(); return; }

        if (foundEnv.weather) this.playLayer('weather', foundEnv.weather);
        if (foundEnv.urban) this.playLayer('urban', foundEnv.urban);
        if (foundEnv.nature) this.playLayer('nature', foundEnv.nature);

        if (foundSfx) {
            this.playSfx(SFX_DB[foundSfx].url);
            if (foundSfx === 'flashback' || foundSfx === 'dejavu' || foundSfx === 'white_noise') {
                const body = document.body;
                body.classList.remove('reading-steiner'); 
                void body.offsetWidth;
                body.classList.add('reading-steiner');
            }
        }
    },

    playLayer(layerName, id) {
        if (this.activeLayers[layerName] === id) return;
        this.activeLayers[layerName] = id;

        const player = document.getElementById(`env-${layerName}`);
        const data = SFX_DB[id];

        player.src = data.url;
        player.volume = this.volumes.sfx * 0.8; 
        player.play().catch(e => console.log("Env Play Error", e));
    },

    stopAllEnv() {
        ['weather', 'urban', 'nature'].forEach(l => {
            const p = document.getElementById(`env-${l}`);
            p.pause();
            this.activeLayers[l] = null;
