    },

    playSfx(url) {
        const player = document.getElementById('sfx-oneshot');
        player.pause();
        player.currentTime = 0;
        player.src = url;
        player.volume = this.volumes.sfx;
        player.play().catch(e => console.log("SFX Play Error", e));
    },

    stopSfx() {
        const player = document.getElementById('sfx-oneshot');
        if(!player.paused) { player.pause(); player.currentTime = 0; }
    },

    bgm(f) {
        const cleanF = f ? f.trim() : "";
        if (!cleanF || this.currBgm === cleanF) return;
        this.currBgm = cleanF;
        const a = document.getElementById('bgm');
        a.src = AssetMgr.getFullUrl(cleanF);
        a.volume = this.volumes.bgm; 
        a.play().catch(e => console.log("BGM Error:", e));
    },

    voice(f) {
        return new Promise((resolve) => {
            const a = document.getElementById('voice');
            if(!f) { a.pause(); resolve(0); return; }
            a.pause(); a.currentTime = 0;
            a.src = f; a.volume = this.volumes.voice;
            let resolved = false;
            a.onloadedmetadata = () => { if(!resolved) { resolved = true; resolve(a.duration); } };
            setTimeout(() => { if(!resolved) { resolved = true; resolve(0); } }, 3000);
            a.onerror = () => { if(!resolved) { resolved = true; resolve(0); } };
            a.play().catch(() => { if(!resolved) { resolved = true; resolve(0); } });
        });
    }
};


